// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb.hypergraph;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.ArrayList;
import java.util.HashSet;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Random;
import java.util.Set;

import org.junit.jupiter.api.Test;

class SubgraphEnumeratorTest {

	/**
	 * Records emissions and verifies the DPhyp contract on every callback: sides disjoint, non-empty, both already seen
	 * (the dynamic-programming order), the reported edge really crosses the cut, the left side carries the lowest-index
	 * node of the union, and no pair is emitted twice.
	 */
	private static final class RecordingReceiver implements SubgraphEnumerator.Receiver {
		private final Hypergraph graph;
		final Set<Long> seen = new HashSet<>();
		final Set<NaiveEnumerator.Pair> pairs = new LinkedHashSet<>();
		final List<Integer> singleNodes = new ArrayList<>();

		private RecordingReceiver(Hypergraph graph) {
			this.graph = graph;
		}

		@Override
		public boolean hasSeen(long nodeSet) {
			return seen.contains(nodeSet);
		}

		@Override
		public boolean foundSingleNode(int nodeIdx) {
			singleNodes.add(nodeIdx);
			seen.add(NodeSets.bit(nodeIdx));
			return false;
		}

		@Override
		public boolean foundSubgraphPair(long left, long right, int edgeIdx) {
			String pair = NodeSets.describe(left) + "|" + NodeSets.describe(right);
			assertFalse(NodeSets.isEmpty(left), pair);
			assertFalse(NodeSets.isEmpty(right), pair);
			assertFalse(NodeSets.overlaps(left, right), pair);
			assertTrue(seen.contains(left), "left not planned before pair " + pair);
			assertTrue(seen.contains(right), "right not planned before pair " + pair);
			long edgeLeft = graph.edgeLeft(edgeIdx);
			long edgeRight = graph.edgeRight(edgeIdx);
			assertTrue((NodeSets.isSubset(edgeLeft, left) && NodeSets.isSubset(edgeRight, right))
					|| (NodeSets.isSubset(edgeLeft, right) && NodeSets.isSubset(edgeRight, left)),
					"edge " + edgeIdx + " does not connect " + pair);
			assertTrue(NodeSets.overlaps(left, NodeSets.lowestBit(left | right)),
					"left side must contain the lowest node of the union: " + pair);
			assertTrue(pairs.add(new NaiveEnumerator.Pair(left, right)), "duplicate pair " + pair);
			seen.add(left | right);
			return false;
		}
	}

	private static RecordingReceiver enumerate(Hypergraph graph) {
		RecordingReceiver receiver = new RecordingReceiver(graph);
		boolean aborted = SubgraphEnumerator.enumerateConnectedPartitions(graph, receiver);
		assertFalse(aborted);
		assertEquals(graph.nodeCount(), receiver.singleNodes.size(), "every node announced exactly once");
		return receiver;
	}

	private static Set<String> describeAll(Set<NaiveEnumerator.Pair> pairs) {
		Set<String> out = new LinkedHashSet<>();
		for (NaiveEnumerator.Pair pair : pairs) {
			out.add(pair.toString());
		}
		return out;
	}

	private static Hypergraph chain(int length) {
		Hypergraph graph = new Hypergraph();
		for (int i = 0; i < length; i++) {
			graph.addNode();
		}
		for (int i = 0; i + 1 < length; i++) {
			graph.addEdge(NodeSets.bit(i), NodeSets.bit(i + 1));
		}
		return graph;
	}

	@Test
	void chainEmitsExactlyTheFourConnectedPairs() {
		// A(0) -- B(1) -- C(2)
		RecordingReceiver receiver = enumerate(chain(3));
		Set<String> pairs = describeAll(receiver.pairs);
		assertEquals(Set.of("{0}|{1}", "{1}|{2}", "{0,1}|{2}", "{0}|{1,2}"), pairs);
	}

	@Test
	void chainNeverEmitsTheDisconnectedPair() {
		RecordingReceiver receiver = enumerate(chain(3));
		for (NaiveEnumerator.Pair pair : receiver.pairs) {
			assertFalse((pair.left() == 0b101L) || (pair.right() == 0b101L),
					"disconnected {A,C} must never appear: " + pair);
		}
	}

	@Test
	void starEmitsOnlyPairsThroughTheCenter() {
		// A(0) center; B(1), C(2), D(3) leaves.
		Hypergraph graph = new Hypergraph();
		for (int i = 0; i < 4; i++) {
			graph.addNode();
		}
		graph.addEdge(NodeSets.bit(0), NodeSets.bit(1));
		graph.addEdge(NodeSets.bit(0), NodeSets.bit(2));
		graph.addEdge(NodeSets.bit(0), NodeSets.bit(3));
		RecordingReceiver receiver = enumerate(graph);
		Set<String> pairs = describeAll(receiver.pairs);
		assertFalse(pairs.contains("{1}|{2}"), "leaf-leaf join without the center is a Cartesian product");
		assertTrue(pairs.contains("{0}|{1}"));
		assertTrue(pairs.contains("{0,2}|{1}"));
		assertTrue(pairs.contains("{0,2,3}|{1}"));
		assertEquals(NaiveEnumerator.allPairs(graph), receiver.pairs);
	}

	@Test
	void triangleCycleMatchesOracle() {
		Hypergraph graph = chain(3);
		graph.addEdge(NodeSets.bit(0), NodeSets.bit(2));
		RecordingReceiver receiver = enumerate(graph);
		assertEquals(NaiveEnumerator.allPairs(graph), receiver.pairs);
		assertEquals(6, receiver.pairs.size(), "three 1|1 pairs and three 2|1 splits");
	}

	@Test
	void hyperedgeGatesTheJoinUntilBothSidesArePresent() {
		// A(0) -- B(1) simple; {A,B} -- {C(2)} hyperedge (e.g. a predicate needing A and B before joining C).
		Hypergraph graph = new Hypergraph();
		for (int i = 0; i < 3; i++) {
			graph.addNode();
		}
		graph.addEdge(NodeSets.bit(0), NodeSets.bit(1));
		graph.addEdge(NodeSets.bit(0) | NodeSets.bit(1), NodeSets.bit(2));
		RecordingReceiver receiver = enumerate(graph);
		assertEquals(Set.of("{0}|{1}", "{0,1}|{2}"), describeAll(receiver.pairs));
	}

	@Test
	void hyperedgeWithInnerEdgeAllowsJoiningTheHypernodeFirst() {
		// {A(0)} -- {B(1),C(2)} hyperedge plus B -- C simple: the outer-join conflict shape from the design doc.
		Hypergraph graph = new Hypergraph();
		for (int i = 0; i < 3; i++) {
			graph.addNode();
		}
		graph.addEdge(NodeSets.bit(1), NodeSets.bit(2));
		graph.addEdge(NodeSets.bit(0), NodeSets.bit(1) | NodeSets.bit(2));
		RecordingReceiver receiver = enumerate(graph);
		assertEquals(Set.of("{1}|{2}", "{0}|{1,2}"), describeAll(receiver.pairs));
	}

	@Test
	void singleNodeGraphEmitsOnlyTheNode() {
		Hypergraph graph = new Hypergraph();
		graph.addNode();
		RecordingReceiver receiver = enumerate(graph);
		assertTrue(receiver.pairs.isEmpty());
		assertEquals(List.of(0), receiver.singleNodes);
	}

	@Test
	void disconnectedGraphEmitsNoCrossComponentPairs() {
		// A(0) -- B(1); C(2) -- D(3); no edges between the components.
		Hypergraph graph = new Hypergraph();
		for (int i = 0; i < 4; i++) {
			graph.addNode();
		}
		graph.addEdge(NodeSets.bit(0), NodeSets.bit(1));
		graph.addEdge(NodeSets.bit(2), NodeSets.bit(3));
		RecordingReceiver receiver = enumerate(graph);
		assertEquals(Set.of("{0}|{1}", "{2}|{3}"), describeAll(receiver.pairs));
	}

	@Test
	void abortFromPairCallbackStopsEnumeration() {
		Hypergraph graph = chain(4);
		List<NaiveEnumerator.Pair> emitted = new ArrayList<>();
		SubgraphEnumerator.Receiver receiver = new SubgraphEnumerator.Receiver() {
			private final Set<Long> seen = new HashSet<>();

			@Override
			public boolean hasSeen(long nodeSet) {
				return seen.contains(nodeSet);
			}

			@Override
			public boolean foundSingleNode(int nodeIdx) {
				seen.add(NodeSets.bit(nodeIdx));
				return false;
			}

			@Override
			public boolean foundSubgraphPair(long left, long right, int edgeIdx) {
				emitted.add(new NaiveEnumerator.Pair(left, right));
				seen.add(left | right);
				return true;
			}
		};
		assertTrue(SubgraphEnumerator.enumerateConnectedPartitions(graph, receiver), "abort must propagate");
		assertEquals(1, emitted.size());
	}

	@Test
	void longChainMatchesOracle() {
		Hypergraph graph = chain(8);
		RecordingReceiver receiver = enumerate(graph);
		assertEquals(NaiveEnumerator.allPairs(graph), receiver.pairs);
	}

	@Test
	void cliqueMatchesOracle() {
		Hypergraph graph = new Hypergraph();
		for (int i = 0; i < 6; i++) {
			graph.addNode();
		}
		for (int i = 0; i < 6; i++) {
			for (int j = i + 1; j < 6; j++) {
				graph.addEdge(NodeSets.bit(i), NodeSets.bit(j));
			}
		}
		RecordingReceiver receiver = enumerate(graph);
		assertEquals(NaiveEnumerator.allPairs(graph), receiver.pairs);
	}

	@Test
	void matchesNaiveOracleOnRandomGraphs() {
		Random random = new Random(20260706L);
		for (int iteration = 0; iteration < 200; iteration++) {
			int iterationNumber = iteration;
			Hypergraph graph = randomGraph(random);
			RecordingReceiver receiver = new RecordingReceiver(graph);
			boolean aborted = SubgraphEnumerator.enumerateConnectedPartitions(graph, receiver);
			assertFalse(aborted);
			Set<NaiveEnumerator.Pair> expected = NaiveEnumerator.allPairs(graph);
			assertEquals(expected, receiver.pairs,
					() -> "iteration " + iterationNumber + " graph:\n" + graph.toDot(i -> "n" + i));
		}
	}

	private static Hypergraph randomGraph(Random random) {
		Hypergraph graph = new Hypergraph();
		int nodeCount = 2 + random.nextInt(8);
		for (int i = 0; i < nodeCount; i++) {
			graph.addNode();
		}
		double edgeProbability = new double[] { 0.15d, 0.3d, 0.6d }[random.nextInt(3)];
		for (int i = 0; i < nodeCount; i++) {
			for (int j = i + 1; j < nodeCount; j++) {
				if (random.nextDouble() < edgeProbability) {
					graph.addEdge(NodeSets.bit(i), NodeSets.bit(j));
				}
			}
		}
		int hyperedges = random.nextInt(4);
		for (int h = 0; h < hyperedges; h++) {
			long left = randomSet(random, nodeCount);
			long right = randomSet(random, nodeCount) & ~left;
			if (!NodeSets.isEmpty(left) && !NodeSets.isEmpty(right)) {
				graph.addEdge(left, right);
			}
		}
		return graph;
	}

	private static long randomSet(Random random, int nodeCount) {
		int size = 1 + random.nextInt(3);
		long set = 0;
		for (int i = 0; i < size; i++) {
			set |= NodeSets.bit(random.nextInt(nodeCount));
		}
		return set;
	}
}
